mapper.select:
SELECT a.id, a.project_id AS "projectId", a.stage_id AS "stageId", a.inspection_items AS "inspectionItems", a.inspection_items AS "items", a.plan_inspection_time AS "planInspectionTime", a.plan_inspection_time AS "inspectionTime", a.site_photos AS "sitePhotos", a.site_photos AS "photos", a.participants, a.signatures, a.passed_at AS "passedAt", a.acceptance_comments AS "acceptanceComments", a.acceptance_comments AS "comments", a.remark, a.inspector_id AS "inspectorId", inspector.name AS "inspectorName", a.result, a.status, CASE WHEN a.status = 3 THEN 'completed' WHEN a.status = 4 THEN 'rectifying' WHEN a.status = 5 THEN 'recheckPending' WHEN a.status = 2 THEN 'processing' ELSE 'pending' END AS "statusCode", CASE WHEN a.status = 3 THEN '已完成' WHEN a.status = 4 THEN '整改中' WHEN a.status = 5 THEN '待复验' WHEN a.status = 2 THEN '验收中' ELSE '待验收' END AS "statusText", a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", s.stage_name AS "stageName", s.stage_name AS "node", u.name AS "createdByName" FROM inspection a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN project_stage s ON s.id = a.stage_id LEFT JOIN sys_account u ON u.id = a.created_by LEFT JOIN sys_account inspector ON inspector.id = a.inspector_id
AND a.project_id = #{params.projectId} AND a.stage_id = #{params.stageId} AND a.created_by = #{params.createdBy}
AND ( a.created_by = #{params.viewerUserId} OR a.inspector_id = #{params.viewerUserId} OR a.participants LIKE CONCAT('%"userId":', #{params.viewerUserId}, '%') OR a.participants LIKE CONCAT('%"userId":"', #{params.viewerUserId}, '"%') OR a.participants LIKE CONCAT('%"userId"%', #{params.viewerUserId}, '%') OR a.participants LIKE CONCAT('%"accountId"%', #{params.viewerUserId}, '%') )
AND ( a.created_by = #{params.viewerUserId} OR a.inspector_id = #{params.viewerUserId} OR a.participants LIKE '%"userId":' || #{params.viewerUserId} || '%' OR a.participants LIKE '%"userId":"' || #{params.viewerUserId} || '"%' OR a.participants LIKE '%"userId"%' || #{params.viewerUserId} || '%' OR a.participants LIKE '%"accountId"%' || #{params.viewerUserId} || '%' )
AND a.status = #{params.status}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.plan_inspection_time >= #{params.startDate} AND a.plan_inspection_time <= #{params.endDate}
ORDER BY a.plan_inspection_time DESC, a.id DESC
